import { MinPriorityQueue } from 'datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Dijkstra's setup: min-heap sorted by time
    const heap = new MinPriorityQueue({ priority: (node) => node.time });
    heap.enqueue({ node: 0, time: 0 });

    // Track the earliest known time to reach each node
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    while (!heap.isEmpty()) {
        const { node: u, time: currentTime } = heap.dequeue().element;

        if (u === n - 1) {
            return currentTime;
        }

        if (currentTime > dist[u]) {
            continue;
        }

        // Option 1: Stay at current node (time +1)
        const nextTime = currentTime + 1;
        if (nextTime < dist[u]) {
            dist[u] = nextTime;
            heap.enqueue({ node: u, time: nextTime });
        }

        // Option 2: Try all outgoing edges
        for (const edge of adj[u]) {
            const { v, start, end } = edge;
            // The earliest we can take this edge is max(currentTime, start)
            const t = Math.max(currentTime, start);
            if (t <= end) {
                const arrivalTime = t + 1;
                if (arrivalTime < dist[v]) {
                    dist[v] = arrivalTime;
                    heap.enqueue({ node: v, time: arrivalTime });
                }
            }
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}
