function solve(n, edges) {
    // Build adjacency list
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push({ v, start, end });
    }

    // Min-heap using a priority queue (simulated with an array and sorting)
    const heap = [];
    const pushHeap = (time, node) => {
        heap.push({ time, node });
        heap.sort((a, b) => a.time - b.time);
    };
    const popHeap = () => heap.shift();

    // Initialize distances with Infinity
    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    pushHeap(0, 0);

    while (heap.length > 0) {
        const { time: currentTime, node: u } = popHeap();
        if (u === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[u]) {
            continue;
        }
        // Option to wait (but only if it helps reach the destination)
        // Instead of explicitly waiting, we consider the earliest possible time to take an edge
        for (const { v, start, end } of adj[u]) {
            // The earliest time we can take this edge is max(currentTime, start)
            const t = Math.max(currentTime, start);
            if (t <= end && t + 1 < dist[v]) {
                dist[v] = t + 1;
                pushHeap(t + 1, v);
            }
        }
    }

    return dist[n - 1] !== Infinity ? dist[n - 1] : -1;
}
